13	const PROCESSING_FEE = 5;
14	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const ITEM_BASE: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_BASE = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const groupCountsByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	};
36	
37	const baseForGroup = (type: string, count: number): number => {
38	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
39	    return COMPONENT_BLOCK_BASE;
40	  }
41	  return count * ITEM_BASE[type];
42	};
43	
44	const calculatePolicyBase = (items: Item[]): number => {
45	  let total = 0;
46	  for (const [type, count] of groupCountsByType(items)) {
47	    total += baseForGroup(type, count);
48	  }
49	  return total;
50	};
51	
52	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
53	
54	const itemSpecificSurcharges = (items: Item[]): number =>
55	  items.reduce((sum, item) => {
56	    const base = ITEM_BASE[item.type];
57	    return sum + (item.cursed ? base * CURSE_SURCHARGE_RATE : 0);
58	  }, 0);
59	
60	const quotePremium = ({ items }: Step): number => {
61	  const policyBase = calculatePolicyBase(items);
62	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
63	  const itemSurcharges = itemSpecificSurcharges(items);
64	  const rawPremium = policyBase + itemSurcharges + firstContractSurcharge + PROCESSING_FEE;
65	  return roundUpInMHPCOsFavor(rawPremium);
66	};
67	
68	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
69	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
70	  return { results };
71	};
